+    const socketUrl = `${sweetLinkEnv.daemonUrl}${SWEETLINK_WS_PATH}`;
+    return {
+        sessionId,
+        sessionToken,
+        socketUrl,
+        expiresAt,
+        secretSource: secretResolution.source,
+    };
