+      const recovered = await tryDevToolsRecovery({
+        sessionUrl: sessionSummary?.url,
+        devtoolsUrl,
+        selector: options.selector,
+        quality,
+        mode,
+        outputPath,
+        prompt,
+        suppressOutput,
+        logInfo,
+        failureReason: result.error,
