+function normalizeScreenshotMethod(input?: string): ScreenshotMethod {
+  if (!input) {
+    return 'auto';
+  }
+  const normalized = input.toLowerCase().trim();
+  switch (normalized) {
+    case 'auto': {
+      return 'auto';
